'use client'
import { useState } from 'react'
import { useProductStore, Product } from '@/store/useProductStore'
import { AddProductModal } from '@/components/products/AddProductModal'
import { DeleteConfirmModal } from '@/components/products/DeleteConfirmModal'
import { TrashIcon, PencilIcon } from '@heroicons/react/24/outline'
import { AddProductButton } from '@/components/products/AddProductButton'

export default function ProductsPage() {
  const products = useProductStore((state) => state.products)
  const deleteProduct = useProductStore((state) => state.deleteProduct)
  
  const [isAddModalOpen, setIsAddModalOpen] = useState(false)
  const [isEditModalOpen, setIsEditModalOpen] = useState(false)
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false)
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null)

  const handleEdit = (product: Product) => {
    setSelectedProduct(product)
    setIsEditModalOpen(true)
  }

  const handleCloseEdit = () => {
    setIsEditModalOpen(false)
    setSelectedProduct(null)
  }

  const handleDelete = (product: Product) => {
    setSelectedProduct(product)
    setIsDeleteModalOpen(true)
  }

  const confirmDelete = () => {
    if (selectedProduct) {
      deleteProduct(selectedProduct.id)
    }
  }

  const handleCloseDelete = () => {
    setIsDeleteModalOpen(false)
    setSelectedProduct(null)
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-gray-900">Products Management</h1>
        <AddProductButton onClick={() => setIsAddModalOpen(true)} />
      </div>

      {products.length > 0 ? (
        <div className="grid gap-4">
          {products.map((product) => (
            <div key={product.id} className="bg-white rounded-xl border border-gray-200 p-6 flex items-center justify-between hover:shadow-sm transition-shadow">
              <div className="flex-1">
                <div className="flex items-center gap-4">
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900">{product.name}</h3>
                    <p className="text-gray-600">{product.category}</p>
                  </div>
                  <div className="text-sm text-gray-500">
                    <span className="bg-gray-50 px-3 py-1 rounded-lg">
                      {product.stock} {product.unit} available
                    </span>
                  </div>
                </div>
              </div>
              
              <div className="flex items-center gap-4">
                <div className="text-right">
                  <div className="text-2xl font-bold text-gray-900">${product.price.toFixed(2)}</div>
                  <div className="text-sm text-gray-500">per {product.unit}</div>
                </div>
                
                <div className="flex gap-2">
                  <button 
                    onClick={() => handleEdit(product)}
                    className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                  >
                    <PencilIcon className="size-4" />
                  </button>
                  <button 
                    onClick={() => handleDelete(product)}
                    className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                  >
                    <TrashIcon className="size-4" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-xl border border-gray-200 p-12 text-center">
          <div className="text-gray-500 mb-4">No products available</div>
          <p className="text-sm text-gray-400">Click "Add Product" to create your first product</p>
        </div>
      )}

      <AddProductModal
        isOpen={isAddModalOpen}
        onClose={() => setIsAddModalOpen(false)}
        mode="add"
      />

      <AddProductModal
        product={selectedProduct || undefined}
        isOpen={isEditModalOpen}
        onClose={handleCloseEdit}
        mode="edit"
      />

      <DeleteConfirmModal
        isOpen={isDeleteModalOpen}
        onClose={handleCloseDelete}
        onConfirm={confirmDelete}
        productName={selectedProduct?.name || ''}
      />
    </div>
  )
}